const cellKey = ([x, y]: Cell): string => `${x},${y}`;
const parseKey = (k: string): Cell => k.split(",").map(Number) as Cell;

/**
 * Computes the next generation of live cells per Conway's Game of Life rules.
 * Returns the set of cells alive after one tick.
 */
export const nextGeneration = (liveCells: Cell[]): Cell[] => {
  const liveKeys = new Set(liveCells.map(cellKey));
  const neighborCounts = new Map<string, number>();
  for (const [x, y] of liveCells) {
    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
      const k = cellKey([x + dx, y + dy]);
      neighborCounts.set(k, (neighborCounts.get(k) ?? 0) + 1);
    }
  }
  const survivesNextTick = (k: string, neighbors: number): boolean =>
    neighbors === 3 || (neighbors === 2 && liveKeys.has(k));
  return [...neighborCounts]
    .filter(([k, count]) => survivesNextTick(k, count))
    .map(([k]) => parseKey(k));
};

